window.docContents[232].resolve({"/Class-Field-Theory-and-Galois-Theory/Power-residue-symbols/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--Class-Field-Theory-and-Galois-Theory--Power-residue-symbols":{"contents":"The power_residue_symbols project (Birkbeck) formalises the -th power residue symbol for\nnumber fields containing the -th roots of unity. The construction of the symbol is the project's\ngoal; it is currently in progress (the uniqueness of the defining root of unity still rests on\nsorrys in the supporting lemmas), and no reciprocity law for the symbol is stated in the project.\n\n\n\n","context":"AINTLIB — An Atlas of Number Theory in Lean\u0009Class Field Theory and Galois Theory","header":"4.7. Power residue symbols","id":"/Class-Field-Theory-and-Galois-Theory/Power-residue-symbols/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--Class-Field-Theory-and-Galois-Theory--Power-residue-symbols"}});